define("mod_booking/sync_rule_modal",["core_form/modalform"],(function(ModalForm){return{init:function(addSelector,actionSelector,cmid,optionid,addTitle,editTitle,deleteTitle,activateTitle){const showModal=function(formClass,args,title,focusElement){const modalForm=new ModalForm({formClass:formClass,args:args,modalConfig:{title:title||""},returnFocus:focusElement||document.body});modalForm.addEventListener(modalForm.events.FORM_SUBMITTED,(function(){window.location.reload()})),modalForm.show()},addButton=document.querySelector(addSelector);addButton&&addButton.addEventListener("click",(function(e){e.preventDefault(),showModal("mod_booking\\form\\sync_rule_form",{cmid:cmid,optionid:optionid,ruleid:0},addTitle||"Add sync rule",addButton)}));const actionButtons=document.querySelectorAll(actionSelector);actionButtons.forEach((function(button){button.addEventListener("click",(function(e){e.preventDefault();const action=button.dataset.action,ruleid=parseInt(button.dataset.ruleid||"0",10);ruleid&&("delete"===action?showModal("mod_booking\\form\\sync_rule_delete_form",{cmid:cmid,optionid:optionid,ruleid:ruleid},deleteTitle||"Delete sync rule",button):"activate"===action?showModal("mod_booking\\form\\sync_rule_activate_form",{cmid:cmid,optionid:optionid,ruleid:ruleid},activateTitle||"Activate sync rule",button):showModal("mod_booking\\form\\sync_rule_form",{cmid:cmid,optionid:optionid,ruleid:ruleid},editTitle||"Edit sync rule",button))}))}))}}}));